oxy_webhelp_navlinks = {"tocId-d26997e8786":{"topics":[{"title":"Users and Access","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides role-based access control, and several methods for authenticating a         user account.<\/p>","href":"saas\/users_access.html","attributes":{"data-id":"users_access"},"menu":{"hasChildren":true},"tocID":"users_access-d26997e8794","next":"users_access-d26997e8794"},{"title":"Quorum authorization","shortdesc":"<p class=\"shortdesc\">Quorum authorization is a security feature that enforces the requirement of getting         additional approvals before a requester can perform data-modifying actions in <span class=\"ph\">RSC<\/span>.<\/p>","href":"qauth\/quorum_authorization.html","attributes":{"data-id":"quorum_authorization"},"menu":{"hasChildren":true},"tocID":"quorum_authorization-d26997e9654","next":"quorum_authorization-d26997e9654"},{"title":"Single sign-on","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> supports SSO using the SAML 2.0 standard. With SSO, you can         log in to <span class=\"ph\">RSC<\/span> using credentials associated with an identity         provider.<\/p>","href":"saas\/single_sign_on.html","attributes":{"data-id":"single_sign_on"},"menu":{"hasChildren":true},"tocID":"single_sign_on-d26997e10199","next":"single_sign_on-d26997e10199"},{"title":"Security settings","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> provides enhanced security authentication services and         features.<\/p>","href":"saas\/rsc_security.html","attributes":{"data-id":"rsc_security"},"menu":{"hasChildren":true},"tocID":"rsc_security-d26997e10852","next":"rsc_security-d26997e10852"}]}};